impl Solution { pub fn can_sort_array(nums: Vec<i32>) -> bool { let (mut black_p_m, mut black_i) = (0, 0); while black_i < nums.len() { let (black_b, mut black_mi, mut black_ma) = (nums[black_i].count_ones(), nums[black_i], nums[black_i]); while black_i < nums.len() && nums[black_i].count_ones() == black_b { black_mi = black_mi.min(nums[black_i]); black_ma = black_ma.max(nums[black_i]); black_i += 1; } if black_mi < black_p_m { return false; } black_p_m = black_ma; } true } }